class Solution:
    def maxActiveSectionsAfterTrade(self, s, queries):
        total_ones = s.count('1')
        answer = []
        for l, r in queries:
            sub = s[l:r + 1]
            ones_sub = sub.count('1')
            t = '1' + sub + '1'
            n = len(t)
            runs = []
            i = 0
            while i < n:
                j = i
                while j < n and t[j] == t[i]:
                    j += 1
                runs.append((i, j, t[i]))
                i = j
            best = ones_sub
            for idx in range(1, len(runs) - 1):
                start, end, ch = runs[idx]
                if ch != '1':
                    continue
                grid = list(t)
                for p in range(start, end):
                    grid[p] = '0'
                left = start
                while left > 0 and grid[left - 1] == '0':
                    left -= 1
                right = end
                while right < n and grid[right] == '0':
                    right += 1
                for p in range(left, right):
                    grid[p] = '1'
                count = ''.join(grid[1:-1]).count('1')
                if count > best:
                    best = count
            gain = best - ones_sub
            answer.append(total_ones + gain)
        return answer

