var maxActiveSectionsAfterTrade = function(s, queries) {
    const n = s.length;
    const runChar = [], runStart = [], runLen = [];
    let i = 0;
    while (i < n) {
        let j = i;
        while (j < n && s[j] === s[i]) j++;
        runChar.push(s[i]);
        runStart.push(i);
        runLen.push(j - i);
        i = j;
    }
    const m = runChar.length;
    const runEnd = new Array(m);
    for (let t = 0; t < m; t++) runEnd[t] = runStart[t] + runLen[t] - 1;
    let totalOnes = 0;
    for (let t = 0; t < n; t++) if (s[t] === '1') totalOnes++;
    const NEG = -1;
    const G = new Array(m).fill(NEG);
    for (let j = 1; j < m - 1; j++) {
        if (runChar[j] === '1') G[j] = runLen[j - 1] + runLen[j + 1];
    }
    const logTable = new Array(m + 1).fill(0);
    for (let v = 2; v <= m; v++) logTable[v] = logTable[Math.floor(v / 2)] + 1;
    const sparse = [G.slice()];
    let k = 1;
    while ((1 << k) <= m) {
        const prev = sparse[sparse.length - 1];
        const half = 1 << (k - 1);
        const length = m - (1 << k) + 1;
        const cur = new Array(length);
        for (let idx = 0; idx < length; idx++) {
            const a = prev[idx], b = prev[idx + half];
            cur[idx] = a > b ? a : b;
        }
        sparse.push(cur);
        k++;
    }
    function rangeMax(l, r) {
        if (l > r) return NEG;
        const length = r - l + 1;
        const kk = logTable[length];
        const a = sparse[kk][l];
        const b = sparse[kk][r - (1 << kk) + 1];
        return a > b ? a : b;
    }
    function runIndex(pos) {
        let lo = 0, hi = m - 1;
        while (lo < hi) {
            const mid = (lo + hi + 1) >> 1;
            if (runStart[mid] <= pos) lo = mid; else hi = mid - 1;
        }
        return lo;
    }
    const answer = [];
    for (const [l, r] of queries) {
        const iL = runIndex(l);
        const iR = runIndex(r);
        if (iL === iR) {
            answer.push(totalOnes);
            continue;
        }
        const lo = iL + 1, hi = iR - 1;
        let best = NEG;
        if (lo <= hi) {
            if (lo + 1 <= hi - 1) {
                const cand = rangeMax(lo + 1, hi - 1);
                if (cand > best) best = cand;
            }
            if (runChar[lo] === '1') {
                const leftLen = runEnd[iL] - l + 1;
                const rightLen = (lo + 1 === iR) ? (r - runStart[iR] + 1) : runLen[lo + 1];
                const cand = leftLen + rightLen;
                if (cand > best) best = cand;
            }
            if (hi !== lo && runChar[hi] === '1') {
                const rightLen = r - runStart[iR] + 1;
                const leftLen = (hi - 1 === iL) ? (runEnd[iL] - l + 1) : runLen[hi - 1];
                const cand = leftLen + rightLen;
                if (cand > best) best = cand;
            }
        }
        const gain = best > 0 ? best : 0;
        answer.push(totalOnes + gain);
    }
    return answer;
};
